body.script:
const terminal = document.getElementById("terminal");

const commands = [

{
cmd:"whoami",
out:'Fulbabu Islam'
},

{
cmd:"education",
out:'B.Tech CSE | J.C. Bose University, YMCA (2023-2027)'
},

{
cmd:"currently",
out:'GSSoC ’26 Contributor'
},

{
cmd:"learning",
out:'Python • AI • MERN'
},

{
cmd:"portfolio",
out:'https://fulbabu.dev'
},

{
cmd:'echo "Turning coffee into code..."',
out:'Turning coffee into code... ☕'
}

];

let speed = 22;
let html = "";

function sleep(ms){
    return new Promise(resolve=>setTimeout(resolve,ms));
}

async function type(text){

    for(let i=0;i<text.length;i++){

        html += text[i];

        terminal.innerHTML =
            html +
            '';

        await sleep(speed);

        terminal.parentElement.scrollTop =
        terminal.parentElement.scrollHeight;

    }

}

async function start(){

    for(let c of commands){

        await type(
            'fulbabu@github:~$ ' +
            c.cmd +
            '\n'
        );

        await sleep(300);

        await type(c.out + "\n\n");

        await sleep(450);

    }

    terminal.innerHTML =
    html +
    'fulbabu@github:~$ ';

}

start();
